// Утилиты и вспомогательные функции

/**
 * Генерирует новый UUID v4
 * @returns {string} UUID в формате xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
 */
export function generateUUID() {
	return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
		var r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8);
		return v.toString(16);
	});
}

export const preViewImage = `data:image/jpeg;base64,`;


/**
 * Преобразует base64 строку в Blob
 * @param {string} base64 - Base64 строка
 * @param {string} mimeType - MIME тип (по умолчанию 'application/octet-stream')
 * @returns {Blob} Blob объект
 */
export function base64ToBlob(base64, mimeType = 'application/octet-stream') {
	try {
		// 1. Извлекаем только саму суть данных
		// Ищем запятую. Если она есть — берем всё после неё.
		let base64Data = base64.indexOf(',') !== -1 ? base64.split(',')[1] : base64;

		// 2. ОЧИСТКА: Удаляем пробелы, переносы строк и любые символы, 
		// которые НЕ могут быть в base64 (на всякий случай)
		base64Data = base64Data.replace(/[^A-Za-z0-9+/=]/g, "");

		// 3. ПРОВЕРКА: Длина строки base64 (без учета padding) должна быть кратна 4
		// (atob иногда прощает отсутствие '=', но лучше почистить)
		const byteCharacters = atob(base64Data);

		const byteArrays = [];
		for (let offset = 0; offset < byteCharacters.length; offset += 512) {
			const slice = byteCharacters.slice(offset, offset + 512);
			const byteNumbers = new Array(slice.length);
			for (let i = 0; i < slice.length; i++) {
				byteNumbers[i] = slice.charCodeAt(i);
			}
			byteArrays.push(new Uint8Array(byteNumbers));
		}
		return new Blob(byteArrays, {
			type: mimeType
		});
	} catch (e) {
		console.error("Ошибка внутри atob! Строка была:", base64.substring(0, 30) + "...");
		throw e;
	}
}

/**
 * Логирует сообщение с префиксом [background]
 * @param {string} message - Сообщение логирования
 * @param {...any} args - Дополнительные аргументы
 */
export function logBackground(message, ...args) {
	console.log(`[background] ${message}`, ...args);
}

/**
 * Логирует ошибку с префиксом [background]
 * @param {string} message - Сообщение ошибки
 * @param {...any} args - Дополнительные аргументы
 */
export function errorBackground(message, ...args) {
	console.error(`[background] ${message}`, ...args);
}

/**
 * Логирует предупреждение с префиксом [background]
 * @param {string} message - Сообщение предупреждения
 * @param {...any} args - Дополнительные аргументы
 */
export function warnBackground(message, ...args) {
	console.warn(`[background] ${message}`, ...args);
}

/**
 * Логирует информацию с префиксом [background]
 * @param {string} message - Информационное сообщение
 * @param {...any} args - Дополнительные аргументы
 */
export function infoBackground(message, ...args) {
	console.info(`[background] ${message}`, ...args);
}
